import { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { useNavigate } from "react-router-dom";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700&family=DM+Sans:wght@300;400;500&display=swap');

  :root {
    --bg: #f5f0e8;
    --surface: #faf7f2;
    --border: #e2d9cc;
    --ink: #1a1612;
    --ink-muted: #7a6f63;
    --accent: #c8441a;
    --accent-hover: #a83515;
    --shadow: 0 2px 12px rgba(26,22,18,0.07);
    --radius: 10px;
    --transition: 200ms cubic-bezier(0.4, 0, 0.2, 1);
  }

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  .profile-root {
    min-height: 100vh;
    background: var(--bg);
    font-family: 'DM Sans', sans-serif;
    color: var(--ink);
    padding: 80px 24px 80px;
  }

  .profile-inner {
    max-width: 680px;
    margin: 0 auto;
  }

  /* ── Header ── */
  .profile-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    margin-bottom: 48px;
    padding-bottom: 20px;
    border-bottom: 1.5px solid var(--border);
  }

  .profile-header h2 {
    font-family: 'Playfair Display', serif;
    font-size: 2.2rem;
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1;
    color: var(--ink);
  }

  .profile-header .dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: var(--accent);
    flex-shrink: 0;
    margin-bottom: 4px;
  }

  /* ── Section labels ── */
  .section-label {
    font-size: 0.7rem;
    font-weight: 500;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--ink-muted);
    margin-bottom: 16px;
  }

  /* ── Create form ── */
  .create-section {
    background: var(--surface);
    border: 1.5px solid var(--border);
    border-radius: var(--radius);
    padding: 28px;
    margin-bottom: 48px;
    box-shadow: var(--shadow);
  }

  .form-group {
    display: flex;
    flex-direction: column;
    gap: 10px;
    margin-bottom: 14px;
  }

  .form-field {
    width: 100%;
    background: var(--bg);
    border: 1.5px solid var(--border);
    border-radius: 7px;
    padding: 11px 14px;
    font-family: 'DM Sans', sans-serif;
    font-size: 0.92rem;
    color: var(--ink);
    outline: none;
    transition: border-color var(--transition), box-shadow var(--transition);
    resize: none;
  }

  .form-field::placeholder {
    color: var(--ink-muted);
    opacity: 0.7;
  }

  .form-field:focus {
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(200, 68, 26, 0.1);
  }

  textarea.form-field {
    min-height: 96px;
    line-height: 1.5;
  }

  .btn-create {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: var(--accent);
    color: #fff;
    border: none;
    border-radius: 7px;
    padding: 11px 22px;
    font-family: 'DM Sans', sans-serif;
    font-size: 0.88rem;
    font-weight: 500;
    letter-spacing: 0.02em;
    cursor: pointer;
    transition: background var(--transition), transform var(--transition), box-shadow var(--transition);
    box-shadow: 0 2px 8px rgba(200, 68, 26, 0.25);
  }

  .btn-create:hover {
    background: var(--accent-hover);
    transform: translateY(-1px);
    box-shadow: 0 4px 14px rgba(200, 68, 26, 0.3);
  }

  .btn-create:active {
    transform: translateY(0);
    box-shadow: none;
  }

  .btn-create svg {
    width: 15px;
    height: 15px;
  }

  /* ── Projects list ── */
  .projects-section {}

  .projects-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
  }

  .project-card {
    background: var(--surface);
    border: 1.5px solid var(--border);
    border-radius: var(--radius);
    padding: 20px 24px;
    cursor: pointer;
    transition: border-color var(--transition), transform var(--transition), box-shadow var(--transition);
    position: relative;
    overflow: hidden;
  }

  .project-card::before {
    content: '';
    position: absolute;
    left: 0; top: 0; bottom: 0;
    width: 3px;
    background: var(--accent);
    opacity: 0;
    transition: opacity var(--transition);
  }

  .project-card:hover {
    border-color: #c8b9a8;
    transform: translateY(-2px);
    box-shadow: var(--shadow);
  }

  .project-card:hover::before {
    opacity: 1;
  }

  .project-card h4 {
    font-family: 'Playfair Display', serif;
    font-size: 1.05rem;
    font-weight: 500;
    color: var(--ink);
    margin-bottom: 5px;
  }

  .project-card p {
    font-size: 0.85rem;
    color: var(--ink-muted);
    line-height: 1.5;
    font-weight: 300;
  }

  .project-arrow {
    position: absolute;
    right: 20px;
    top: 50%;
    transform: translateY(-50%) translateX(4px);
    opacity: 0;
    color: var(--accent);
    transition: opacity var(--transition), transform var(--transition);
    font-size: 1.1rem;
  }

  .project-card:hover .project-arrow {
    opacity: 1;
    transform: translateY(-50%) translateX(0);
  }

  /* ── Empty state ── */
  .empty-state {
    text-align: center;
    padding: 56px 24px;
    border: 1.5px dashed var(--border);
    border-radius: var(--radius);
    color: var(--ink-muted);
  }

  .empty-state .empty-icon {
    font-size: 2rem;
    margin-bottom: 12px;
    opacity: 0.5;
  }

  .empty-state p {
    font-size: 0.9rem;
    font-weight: 300;
  }
`;

export default function Profile() {
  const [user, setUser] = useState(null);
  const [projects, setProjects] = useState([]);
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");

  const navigate = useNavigate();

  useEffect(() => {
    getUser();
  }, []);

  const getUser = async () => {
    const { data } = await supabase.auth.getUser();
    const currentUser = data.user;
    setUser(currentUser);
    if (currentUser) fetchProjects(currentUser.id);
  };

  const fetchProjects = async (userId) => {
    const { data, error } = await supabase
      .from("projects")
      .select("*")
      .eq("user_id", userId)
      .order("created_at", { ascending: false });

    if (error) { console.log(error); return; }

    const safeProjects = (data || []).filter((proj) => proj.user_id === userId);
    setProjects(safeProjects);
  };

  const createProject = async () => {
    if (!user) { alert("User not loaded"); return; }
    if (!title.trim()) { alert("Enter project title"); return; }

    const { error } = await supabase.from("projects").insert([
      { user_id: user.id, title, description },
    ]);

    if (error) { console.log(error); return; }

    setTitle("");
    setDescription("");
    fetchProjects(user.id);
  };

  // 🔥 DELETE PROJECT
const deleteProject = async (projectId) => {
  if (!user) {
    alert("User not found");
    return;
  }

  const confirmDelete = window.confirm(
    "Delete this project?\nThis will remove all community data."
  );
  if (!confirmDelete) return;

  // 🔒 verify ownership
  const { data: project } = await supabase
    .from("projects")
    .select("user_id")
    .eq("id", projectId)
    .single();

  if (!project || project.user_id !== user.id) {
    alert("You are not allowed to delete this project");
    return;
  }

  const { error } = await supabase
    .from("projects")
    .delete()
    .eq("id", projectId);

  if (error) {
    console.log(error);
    alert("Delete failed");
    return;
  }

  // 🔥 update UI
  setProjects((prev) => prev.filter((p) => p.id !== projectId));
};

  return (
    <>
      <style>{styles}</style>
      <div className="profile-root">
        <div className="profile-inner">

          {/* Header */}
          <div className="profile-header">
            <h2>My Profile</h2>
            <div className="dot" />
          </div>

          {/* Create Project */}
          <div className="create-section">
            <p className="section-label">New Project</p>
            <div className="form-group">
              <input
                className="form-field"
                placeholder="Project title"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
              />
              <textarea
                className="form-field"
                placeholder="Short description (optional)"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>
            <button className="btn-create" onClick={createProject}>
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" />
              </svg>
              Create Project
            </button>
          </div>

          {/* Projects List */}
          <div className="projects-section">
            <p className="section-label">My Projects ({projects.length})</p>

            {projects.length === 0 ? (
              <div className="empty-state">
                <div className="empty-icon">◻</div>
                <p>No projects yet — create your first one above.</p>
              </div>
            ) : (
              <div className="projects-list">
                {projects.map((proj) => (
                  <div
                    key={proj.id}
                    className="project-card"
                    onClick={() => navigate(`/project/${proj.id}`)}
                  >
                    <h4>{proj.title}</h4>
                    {proj.description && <p>{proj.description}</p>}
                    <span className="project-arrow">→</span>
                  </div>
                ))}
              </div>
            )}
          </div>

        </div>
      </div>
    </>
  );
}
